### 3.2 Python（使用 `defaultdict` 计数）

```python
import sys
sys.setrecursionlimit(1 << 25)
from collections import defaultdict

def readints():
    return map(int, sys.stdin.readline().split())

N = int(sys.stdin.readline())
col = [0] + list(readints())          # 1-indexed
g = [[] for _ in range(N + 1)]
for _ in range(N - 1):
    u, v = map(int, sys.stdin.readline().split())
    g[u].append(v)
    g[v].append(u)

sz = [0] * (N + 1)
big = [-1] * (N + 1)

def dfs_sz(u, p):
    sz[u] = 1
    big[u] = -1
    for v in g[u]:
        if v == p: continue
        dfs_sz(v, u)
        sz[u] += sz[v]
        if big[u] == -1 or sz[v] > sz[big[u]]:
            big[u] = v

cnt = defaultdict(int)      # color -> frequency in current counter
freqCnt = defaultdict(int)  # frequency -> how many colors have this freq
maxFreq = 0
ans = [0] * (N + 1)

def add_subtree(u, p, delta):
    """ delta = +1 (add) or -1 (remove) """
    nonlocal maxFreq
    c = col[u]
    if delta == 1:
        freqCnt[cnt[c]] -= 1
        cnt[c] += 1
        freqCnt[cnt[c]] += 1
        maxFreq = max(maxFreq, cnt[c])
    else:
        freqCnt[cnt[c]] -= 1
        cnt[c] -= 1
        freqCnt[cnt[c]] += 1
        # 如果当前 maxFreq 没有颜色了，需要向下找
        if freqCnt[maxFreq] == 0:
            maxFreq -= 1

    for v in g[u]:
        if v == p or v == big[u]:
            continue
        add_subtree(v, u, delta)

def dfs(u, p, keep):
    # 轻儿子
    for v in g[u]:
        if v == p or v == big[u]:
            continue
        dfs(v, u, False)

    # 重儿子
    if big[u] != -1:
        dfs(big[u], u, True)

    # 合并轻儿子的信息
    for v in g[u]:
        if v == p or v == big[u]:
            continue
        add_subtree(v, u, +1)

    # 加上自己
    add_subtree(u, p, +1)

    # 当前子树的答案
    ans[u] = maxFreq

    # 若不保留，全部撤销
    if not keep:
        add_subtree(u, p, -1)
        # 重置 maxFreq（因为全部删光了）
        nonlocal_max = max(cnt.values(), default=0)
        maxFreq = nonlocal_max

dfs_sz(1, 0)
dfs(1, 0, True)

print(' '.join(map(str, ans[1:])))
```

> **Python 小技巧**  
> - 用 `defaultdict(int)` 免掉判空。  
> - `maxFreq` 的维护在删操作时可用 `while freqCnt[maxFreq] == 0: maxFreq -= 1`（平均仍是 `O(1)`）。  
> - 若颜色范围非常大，建议先 **离散化**（`sorted(set(col[1:]))`），这样 `cnt` 仍可以用普通 `list`，性能更佳。

