    for (int v : g[u]) if (v != p) {
        dfs_sz(v, u);
        sz[u] += sz[v];
        if (bigChild[u] == -1 || sz[v] > sz[bigChild[u]])
            bigChild[u] = v;
    }
}

// 把子树 u（不包括重儿子）全部加入/删除，delta = +1 / -1
void add_subtree(int u, int p, int delta) {
    int c = col[u];
    if (delta == 1) {
        // 移除旧的 freqCnt
        freqCnt[cnt[c]]--;
        cnt[c]++;
        freqCnt[cnt[c]]++;
        maxFreq = max(maxFreq, cnt[c]);
    } else {
        freqCnt[cnt[c]]--;
        cnt[c]--;
        freqCnt[cnt[c]]++;
        // 如果删除后 maxFreq 对应的颜色数为 0，需要向下找
        if (freqCnt[maxFreq] == 0) maxFreq--;
    }

    for (int v : g[u]) if (v != p && v != bigChild[u])
        add_subtree(v, u, delta);
}

void dfs(int u, int p, bool keep) {
    // 处理所有轻儿子
    for (int v : g[u]) if (v != p && v != bigChild[u])
        dfs(v, u, false);

    // 处理重儿子
    if (bigChild[u] != -1) dfs(bigChild[u], u, true);

    // 把轻儿子的信息合并进来
    for (int v : g[u]) if (v != p && v != bigChild[u])
        add_subtree(v, u, +1);

    // 加上当前结点
    int c = col[u];
    freqCnt[cnt[c]]--;
    cnt[c]++;
    freqCnt[cnt[c]]++;
    maxFreq = max(maxFreq, cnt[c]);

    // 当前子树 u 的答案
    ans[u] = maxFreq;

    // 若不保留，全部删掉
    if (!keep) {
        add_subtree(u, p, -1);
        maxFreq = 0;                 // 恢复到初始状态（freqCnt 全部为 0）
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    cin >> N;
    for (int i = 1; i <= N; ++i) cin >> col[i];
    for (int i = 0; i < N-1; ++i) {
        int u, v; cin >> u >> v;
        g[u].push_back(v);
        g[v].push_back(u);
    }

    dfs_sz(1, 0);
    dfs(1, 0, true);

    for (int i = 1; i <= N; ++i)
        cout << ans[i] << (i==N?'\n':' ');
    return 0;
}
