## 4. A clean, self‑contained DSU‑on‑Tree template  

Below is a **ready‑to‑paste** version that follows the usual “small‑to‑large” pattern, computes the **sum of values in each component after removing an edge**, and works for a forest.  

```cpp
#include <bits/stdc++.h>
using namespace std;

using ll = long long;

/* ----------  data structure for the “bag”  ---------- */
struct Bag {
    // we keep a simple hash‑map + a running total.
    // change this if you need a more complex query (e.g. sum of squares).
    unordered_map<int, ll> mp;
    ll total = 0;                     // sum of all (value * count)

    void clear() { mp.clear(); total = 0; }

    // delta can be positive (add) or negative (remove)
    void add(int key, ll delta) {
        ll &cur = mp[key];
        cur += delta;
        total += delta;
        if (cur == 0) mp.erase(key); // keep map small
    }
    ll query() const { return total; }   // change if you need something else
};

/* ----------  global containers  ---------- */
int N;                                   // number of vertices (1‑based)
vector<vector<int>> g;                  // adjacency list
vector<vector<pair<int,ll>>> cols;      // cols[v] = list of (key, value)

vector<int> sz;                          // subtree size (by vertex count)
vector<int> heavy;                       // heavy child (‑1 = none)
vector<char> seen;                      // visited flag for dfsinit
vector<ll> answer;                       // answer per edge (size = M)
vector<pair<int,int>> edges;             // original edges (0‑based index)

unordered_map<long long,int> edgeId;     // encode (u,v) → id (u<v)
inline long long encode(int a, int b){ return ( (long long)min(a,b) << 32 ) | max(a,b); }

/* ----------  first dfs – compute heavy child  ---------- */
void dfsInit(int u, int p)
{
    seen[u] = 1;
    sz[u] = 1;
    heavy[u] = -1;
    for (int v : g[u]) if (v != p) {
        dfsInit(v, u);
        sz[u] += sz[v];
        if (heavy[u] == -1 || sz[v] > sz[heavy[u]]) heavy[u] = v;
    }
}

/* ----------  helper to add a whole subtree  ---------- */
void addSubtree(Bag &bag, int u, int p, ll sign)   // sign = +1 → add, -1 → remove
{
    for (auto [k,val] : cols[u]) bag.add(k, sign * val);
    for (int v : g[u]) if (v != p) addSubtree(bag, v, u, sign);
}

/* ----------  DSU‑on‑Tree recursion  ---------- */
void dsuOnTree(int u, int p, bool keep, Bag &bag, const ll totalComponent)
{
    // 1) process all light children (discard after returning)
    for (int v : g[u]) if (v != p && v != heavy[u])
        dsuOnTree(v, u, false, bag, totalComponent);

    // 2) process heavy child (keep its data)
    if (heavy[u] != -1)
        dsuOnTree(heavy[u], u, true, bag, totalComponent);

    // 3) merge light children into the heavy bag
    for (int v : g[u]) if (v != p && v != heavy[u])
        addSubtree(bag, v, u, +1);

    // 4) finally add the current vertex itself
    for (auto [k,val] : cols[u]) bag.add(k, val);

    // 5) answer for the edge (u , p)  – if p != 0 (root of a component)
    if (p != 0) {
        ll subtreeSum = bag.query();               // sum inside u‑side
        answer[ edgeId[ encode(u,p) ] ] = subtreeSum + (totalComponent - subtreeSum);
    }

    // 6) if we are not supposed to keep the data, erase the whole subtree
    if (!keep) addSubtree(bag, u, p, -1);
}

