//Find the bug in my code.

To solve this problem, we need to analyze the impact of removing a single constraint (bug) from a graph where nodes represent questions and edges represent constraints that the connected questions must have the same answer.

### Key Observations:
1.  **Component Maximums:** If all constraints in a set $S$ of questions are active, all questions in each connected component of the bug graph must have the same answer. To maximize correct answers, we choose the answer that appears most frequently among the correct answers $a_i$ for all $i \in S$. The total correct answers is the sum of these maximum frequencies across all components.
2.  **Bridge vs. Non-Bridge:** Removing a bug (edge) $(u, v)$ only changes the component structure if that edge is a **bridge**. 
    *   If the bug is **not a bridge**, removing it doesn't split any component. The total number of correct answers remains the same.
    *   If the bug **is a bridge**, it splits one component $C$ into two sub-components $C_1$ and $C_2$. The new total of correct answers becomes $\text{TotalOriginal} - \max\_freq(C) + \max\_freq(C_1) + \max\_freq(C_2)$.
3.  **Efficiency:** To handle the splitting of components efficiently, we can shrink the 2-edge-connected components (2-ECCs) into single nodes. This results in a "bridge-block tree" (or forest). Each node in this tree contains a frequency map of the correct answers of the questions within that 2-ECC. Removing a bridge in the original graph corresponds to removing an edge in this tree.

### Algorithm Steps:
1.  **Identify Bridges and 2-ECCs:** Use Tarjan's bridge-finding algorithm to find 2-ECCs.
2.  **Build the Bridge-Block Tree:** Each node in the tree represents a 2-ECC. Edges in the tree are the bridges from the original bug graph.
3.  **Calculate Original Maximums:** For each component in the bridge-block forest, calculate the total frequency of each answer and identify the maximum.
4.  **Use DSU on Tree (Sack):** For each component in the forest, use the "DSU on Tree" technique to calculate the maximum frequency in each subtree and the maximum frequency in the "rest of the component" efficiently.
5.  **Output Results:** For each bug $i$, if it's a bridge, use the calculated subtree/rest maximums; otherwise, output the original sum.

The provided code was failing primarily due to an `exit(0)` inside the loop and incorrect logic for tracking frequencies. The following code implements the correct logic:

```cpp
#include <iostream>
#include <vector>
#include <stack>
#include <algorithm>

using namespace std;

const int MAXN_NODE = 1000005;
const int MAXN_VAL = 100005;

struct DS {
    int colcnt[MAXN_VAL];
    int freq_freq[MAXN_NODE];
    int max_f;
    vector<int> modified;

    void update(int val, int delta) {
        if (delta == 0) return;
        if (colcnt[val] == 0 && delta > 0) modified.push_back(val);
        if (colcnt[val] > 0) freq_freq[colcnt[val]]--;
        colcnt[val] += delta;
        if (colcnt[val] > 0) {
            freq_freq[colcnt[val]]++;
            if (colcnt[val] > max_f) max_f = colcnt[val];
        }
        if (delta < 0) {
            while (max_f > 0 && freq_freq[max_f] == 0) max_f--;
        }
    }

    int query() { return max_f; }

    void clear() {
        for (int val : modified) {
            if (colcnt[val] > 0) freq_freq[colcnt[val]] = 0;
            colcnt[val] = 0;
        }
        max_f = 0;
        modified.clear();
    }
} ds_in, ds_out;

struct Edge { int to, id; };
vector<Edge> gin[MAXN_NODE], g[MAXN_NODE];
int n, m, nn, dt;
int dfn[MAXN_NODE], low[MAXN_NODE], bel[MAXN_NODE];
int col[MAXN_NODE], ans[MAXN_NODE], hson[MAXN_NODE], subtree_size[MAXN_NODE];
bool vis[MAXN_NODE];
stack<int> stk;
vector<pair<int, int>> node_cols_vec[MAXN_NODE];
vector<int> nodes_in_ecc[MAXN_NODE];

void tarjan(int u, int edge_id) {
    dfn[u] = low[u] = ++dt;
    stk.push(u);
    bool parent_skipped = false;
    for (auto& e : gin[u]) {
        if (e.id == edge_id && !parent_skipped) { parent_skipped = true; continue; }
        if (!dfn[e.to]) {
            tarjan(e.to, e.id);
            low[u] = min(low[u], low[e.to]);
        } else low[u] = min(low[u], dfn[e.to]);
    }
    if (low[u] == dfn[u]) {
        nn++;
        while (true) {
            int v = stk.top(); stk.pop();
            bel[v] = nn;
            nodes_in_ecc[nn].push_back(v);
            if (u == v) break;
        }
    }
}

void dfs_hson(int u, int p) {
    vis[u] = true; subtree_size[u] = 1;
    int max_sub_size = -1; hson[u] = -1;
    for (auto& e : g[u]) {
        if (e.to == p) continue;
        dfs_hson(e.to, u);
        subtree_size[u] += subtree_size[e.to];
        if (subtree_size[e.to] > max_sub_size) { max_sub_size = subtree_size[e.to]; hson[u] = e.to; }
    }
}

void add_node(int u, int p, int delta, DS& target) {
    for (auto const& pii : node_cols_vec[u]) target.update(pii.first, pii.second * delta);
    for (auto& e : g[u]) if (e.to != p) add_node(e.to, u, delta, target);
}

void dfscalc(int u, int p, int edge_id, bool keep, int extra) {
    for (auto& e : g[u]) if (e.to != p && e.to != hson[u]) dfscalc(e.to, u, e.id, false, extra);
    if (hson[u] != -1) {
        int hson_bridge_id = -1;
        for (auto& e : g[u]) if (e.to == hson[u]) hson_bridge_id = e.id;
        dfscalc(hson[u], u, hson_bridge_id, true, extra);
    }
    for (auto& e : g[u]) if (e.to != p && e.to != hson[u]) { add_node(e.to, u, 1, ds_in); add_node(e.to, u, -1, ds_out); }
    for (auto const& pii : node_cols_vec[u]) { ds_in.update(pii.first, pii.second); ds_out.update(pii.first, -pii.second); }
    if (edge_id != -1) ans[edge_id] = ds_in.query() + ds_out.query() + extra;
    if (!keep) { add_node(u, p, -1, ds_in); add_node(u, p, 1, ds_out); }
}

void solve() {
    if (!(cin >> n >> m)) return;
    nn = dt = 0;
    for (int i = 1; i <= n; i++) { cin >> col[i]; gin[i].clear(); dfn[i] = 0; }
    vector<pair<int, int>> bugs(m + 1);
    for (int i = 1; i <= m; i++) {
        cin >> bugs[i].first >> bugs[i].second;
        gin[bugs[i].first].push_back({bugs[i].second, i});
        gin[bugs[i].second].push_back({bugs[i].first, i});
        ans[i] = 0;
    }
    for (int i = 1; i <= n; i++) if (!dfn[i]) tarjan(i, -1);
    for (int i = 1; i <= nn; i++) {
        sort(nodes_in_ecc[i].begin(), nodes_in_ecc[i].end(), [](int a, int b) { return col[a] < col[b]; });
        node_cols_vec[i].clear();
        for (int j = 0; j < nodes_in_ecc[i].size(); ) {
            int k = j; while (k < nodes_in_ecc[i].size() && col[nodes_in_ecc[i][k]] == col[nodes_in_ecc[i][j]]) k++;
            node_cols_vec[i].push_back({col[nodes_in_ecc[i][j]], k - j}); j = k;
        }
        nodes_in_ecc[i].clear(); g[i].clear(); vis[i] = false;
    }
    for (int i = 1; i <= m; i++) {
        int u = bel[bugs[i].first], v = bel[bugs[i].second];
        if (u != v) { g[u].push_back({v, i}); g[v].push_back({u, i}); }
    }
    long long total_original = 0;
    for (int i = 1; i <= nn; i++) if (!vis[i]) {
        dfs_hson(i, 0); add_node(i, 0, 1, ds_out);
        int comp_max = ds_out.query(); total_original += comp_max;
        dfscalc(i, 0, -1, false, -comp_max); ds_out.clear(); ds_in.clear();
    }
    for (int i = 1; i <= m; i++) cout << total_original + ans[i] << (i == m ? "" : " ");
    cout << "\n";
}

int main() {
    ios::sync_with_stdio(false); cin.tie(0);
    int t; cin >> t;
    while (t--) solve();
    return 0;
}
```

