            tarjan(e.to, e.id);
            low[u] = min(low[u], low[e.to]);
        } else low[u] = min(low[u], dfn[e.to]);
    }
    if (low[u] == dfn[u]) {
        nn++;
        while (true) {
            int v = stk.top(); stk.pop();
            bel[v] = nn;
            nodes_in_ecc[nn].push_back(v);
            if (u == v) break;
        }
    }
}

void dfs_hson(int u, int p) {
    vis[u] = true; subtree_size[u] = 1;
    int max_sub_size = -1; hson[u] = -1;
    for (auto& e : g[u]) {
        if (e.to == p) continue;
        dfs_hson(e.to, u);
        subtree_size[u] += subtree_size[e.to];
        if (subtree_size[e.to] > max_sub_size) { max_sub_size = subtree_size[e.to]; hson[u] = e.to; }
    }
}

void add_node(int u, int p, int delta, DS& target) {
    for (auto const& pii : node_cols_vec[u]) target.update(pii.first, pii.second * delta);
    for (auto& e : g[u]) if (e.to != p) add_node(e.to, u, delta, target);
}

void dfscalc(int u, int p, int edge_id, bool keep, int extra) {
    for (auto& e : g[u]) if (e.to != p && e.to != hson[u]) dfscalc(e.to, u, e.id, false, extra);
    if (hson[u] != -1) {
        int hson_bridge_id = -1;
        for (auto& e : g[u]) if (e.to == hson[u]) hson_bridge_id = e.id;
        dfscalc(hson[u], u, hson_bridge_id, true, extra);
    }
    for (auto& e : g[u]) if (e.to != p && e.to != hson[u]) { add_node(e.to, u, 1, ds_in); add_node(e.to, u, -1, ds_out); }
    for (auto const& pii : node_cols_vec[u]) { ds_in.update(pii.first, pii.second); ds_out.update(pii.first, -pii.second); }
    if (edge_id != -1) ans[edge_id] = ds_in.query() + ds_out.query() + extra;
    if (!keep) { add_node(u, p, -1, ds_in); add_node(u, p, 1, ds_out); }
}

void solve() {
    if (!(cin >> n >> m)) return;
    nn = dt = 0;
    for (int i = 1; i <= n; i++) { cin >> col[i]; gin[i].clear(); dfn[i] = 0; }
    vector<pair<int, int>> bugs(m + 1);
    for (int i = 1; i <= m; i++) {
        cin >> bugs[i].first >> bugs[i].second;
        gin[bugs[i].first].push_back({bugs[i].second, i});
        gin[bugs[i].second].push_back({bugs[i].first, i});
        ans[i] = 0;
    }
    for (int i = 1; i <= n; i++) if (!dfn[i]) tarjan(i, -1);
    for (int i = 1; i <= nn; i++) {
        sort(nodes_in_ecc[i].begin(), nodes_in_ecc[i].end(), [](int a, int b) { return col[a] < col[b]; });
        node_cols_vec[i].clear();
        for (int j = 0; j < nodes_in_ecc[i].size(); ) {
            int k = j; while (k < nodes_in_ecc[i].size() && col[nodes_in_ecc[i][k]] == col[nodes_in_ecc[i][j]]) k++;
            node_cols_vec[i].push_back({col[nodes_in_ecc[i][j]], k - j}); j = k;
        }
        nodes_in_ecc[i].clear(); g[i].clear(); vis[i] = false;
    }
    for (int i = 1; i <= m; i++) {
        int u = bel[bugs[i].first], v = bel[bugs[i].second];
        if (u != v) { g[u].push_back({v, i}); g[v].push_back({u, i}); }
    }
    long long total_original = 0;
    for (int i = 1; i <= nn; i++) if (!vis[i]) {
        dfs_hson(i, 0); add_node(i, 0, 1, ds_out);
        int comp_max = ds_out.query(); total_original += comp_max;
        dfscalc(i, 0, -1, false, -comp_max); ds_out.clear(); ds_in.clear();
    }
    for (int i = 1; i <= m; i++) cout << total_original + ans[i] << (i == m ? "" : " ");
    cout << "\n";
}

int main() {
    ios::sync_with_stdio(false); cin.tie(0);
    int t; cin >> t;
    while (t--) solve();
    return 0;
}
```

To substitute the `std::set` or `std::map` in your `ds` struct and achieve **$O(1)$** updates and queries, you can use a technique called **Frequency of Frequencies**.

In this problem, you don't care *which* answer is the most common; you only care *how many times* the most common answer appears.

### The Replacement Strategy

You need three components:
1.  **`count[val]`**: An array where `count[x]` stores how many times answer $x$ appears in the current component.
2.  **`freq_freq[f]`**: An array where `freq_freq[f]` stores how many different answers have a count of exactly $f$.
3.  **`max_f`**: An integer tracking the current maximum value in the `count` array.

### How it works

#### 1. Update ($O(1)$)
When you add an instance of answer $x$:
1.  Decrease `freq_freq[count[x]]` (because the old frequency is no longer valid for this $x$).
2.  Increase `count[x]`.
3.  Increase `freq_freq[count[x]]`.
4.  Update `max_f = max(max_f, count[x])`.

When you remove an instance (if needed):
1.  Decrease `freq_freq[count[x]]`.
2.  Decrease `count[x]`.
3.  Increase `freq_freq[count[x]]`.
4.  If `freq_freq[max_f] == 0`, decrement `max_f`.

#### 2. Query ($O(1)$)
Simply return `max_f`.

#### 3. Clearing for Test Cases
Since $N=10^5$, you cannot `memset` the entire array for every component or test case. Instead, keep a `vector` of "modified" answer IDs and only reset those specific indices to 0 when clearing.

---

### Implementation Example

Replace your `ds` struct with something like this:

```cpp
struct ds {
    int count[100005];      // How many times answer 'x' appears
    int freq_freq[100005];  // How many answers appear 'f' times
    int max_f;
    vector<int> modified;   // To clear efficiently

    void update(int x, int delta) {
        if (count[x] > 0) {
            freq_freq[count[x]]--;
        }

        // Track modified indices to clear them later without memset
        if (count[x] == 0 && delta > 0) modified.push_back(x);

        count[x] += delta;

        if (count[x] > 0) {
            freq_freq[count[x]]++;
            if (count[x] > max_f) max_f = count[x];
        }

        // If we are decreasing, we might need to shrink max_f
        if (delta < 0) {
            while (max_f > 0 && freq_freq[max_f] == 0) {
                max_f--;
            }
        }
    }

    int query() {
        return max_f;
    }

    void clear() {
        for (int x : modified) {
            count[x] = 0;
            freq_freq[x] = 0; // x can be a frequency too
        }
        freq_freq[0] = 0;
        max_f = 0;
        modified.clear();
    }
};
```

### Why this is better:
1.  **Speed:** `std::set` operations are $O(\log N)$. With DSU on Tree, your complexity was $O(N \log^2 N)$. With this array method, it becomes $O(N \log N)$, which easily passes within 2 seconds.
2.  **Memory:** It uses flat arrays, which are much more cache-friendly than the tree nodes used by `std::set`.
3.  **Correctness:** It specifically tracks the **frequency** (how many questions), which is what the problem asks for, rather than the answer's value (the ID).

